17	pub struct Caching<R: RbRef, const P: bool, const C: bool> {
18	    frozen: Frozen<R, P, C>,
19	}
20	
21	/// Caching producer implementation.
22	pub type CachingProd<R> = Caching<R, true, false>;
23	/// Caching consumer implementation.
